exports.code = async (inputs) => {
    let list = null;

    // 코드 노드에 입력된 모든 변수를 하나씩 뒤집니다.
    for (const key in inputs) {
        let val = inputs[key];

        // 1. 문자열로 들어온 경우 JSON 배열 파싱 시도
        if (typeof val === 'string') {
            try {
                val = JSON.parse(val);
            } catch (e) {}
        }

        // 2. 바로 배열 형태를 찾은 경우 채택
        if (Array.isArray(val)) {
            list = val;
            break;
        }

        // 3. Storage Get 결과 객체 속에서 배열을 찾은 경우 채택
        if (val && typeof val === 'object') {
            if (Array.isArray(val.value)) {
                list = val.value;
                break;
            }
            if (val.key && val.value) {
                let innerVal = val.value;
                if (typeof innerVal === 'string') {
                    try { innerVal = JSON.parse(innerVal); } catch(e) {}
                }
                if (Array.isArray(innerVal)) {
                    list = innerVal;
                    break;
                }
            }
        }
    }

    // 배열을 찾지 못한 경우 빈 배열로 세팅
    if (!list || !Array.isArray(list)) {
        list = [];
    }

    // 중복 제거 처리
    const uniqueList = [...new Set(list)];

    return { list: uniqueList };
};

const axios = require('axios');
const cheerio = require('cheerio');

// 두 좌표 간 직선 거리(km) 계산 (하버사인 공식)
function calculateDistance(lat1, lon1, lat2, lon2) {
    const R = 6371.0; 
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = 
        Math.sin(dLat / 2) * Math.sin(dLat / 2) +
        Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * 
        Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
}

// 만능 재귀적 키-값 추출기 (정규식 백업 파싱 포함)
function findValueByKey(obj, targetKey) {
    if (!obj || typeof obj !== 'object') return undefined;
    if (obj[targetKey] !== undefined) return obj[targetKey];
    for (const key in obj) {
        const val = obj[key];
        if (typeof val === 'string') {
            try {
                const fixedVal = val.replace(/([a-zA-Z0-9_]+)\s*:/g, '"$1":').replace(/'/g, '"');
                const parsed = JSON.parse(fixedVal);
                if (parsed && typeof parsed === 'object') {
                    const found = findValueByKey(parsed, targetKey);
                    if (found !== undefined) return found;
                }
            } catch (e) {
                const cleanVal = val.replace(/\\"/g, '"').replace(/\\'/g, "'");
                const regex = new RegExp(`['"]?${targetKey}['"]?\\s*:\\s*([^\\n,]+)`);
                const match = cleanVal.match(regex);
                if (match) {
                    const strVal = match[1].replace(/[\[\]'"{}\\\\]/g, '').trim();
                    if (strVal) return strVal;
                }

                const regexNum = new RegExp(`['"]?${targetKey}['"]?\\s*:\\s*([0-9.]+)`);
                const matchNum = val.match(regexNum);
                if (matchNum) {
                    return matchNum[1];
                }
            }
        } else if (val && typeof val === 'object') {
            const found = findValueByKey(val, targetKey);
            if (found !== undefined) return found;
        }
    }
    return undefined;
}

// 1. 고용24 (워크넷) 크롤러
async function scrapeWorknet(keyword) {
    const encodedKeyword = encodeURIComponent(keyword);
    const url = `https://www.work.go.kr/empInfo/empInfoSrch/list/dtlEmpSrchList.do?searchOn=Y&srcKeyword=${encodedKeyword}`;
    const headers = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
    };

    const jobs = [];
    try {
        const response = await axios.get(url, { headers, timeout: 10000 });
        if (response.status === 200) {
            const $ = cheerio.load(response.data);
            const jobRows = $("table.board-list tbody tr");

            jobRows.each((index, element) => {
                const row = $(element);
                const tds = row.find("td");
                if (tds.length < 3) return;

                const companyElement = row.find("a.cp_name");
                const company = companyElement.length ? companyElement.text().trim() : "회사명 비공개";

                const cpInfoDiv = row.find("td").eq(2).find(".cp-info");
                if (cpInfoDiv.length === 0) return;

                const titleElement = cpInfoDiv.find("a").first();
                if (titleElement.length === 0) return;

                const title = titleElement.text().trim();
                let link = titleElement.attr('href') || '';
                if (link && !link.startsWith('http')) {
                    link = "https://www.work24.go.kr" + link;
                }

                const ems = cpInfoDiv.find("em");
                let career = "관계없음";
                let education = "학력무관";
                let address = "";

                if (ems.length >= 3) {
                    career = $(ems[0]).text().trim();
                    education = $(ems[1]).text().trim();
                    address = $(ems[2]).text().trim();
                } else if (ems.length === 2) {
                    career = $(ems[0]).text().trim();
                    address = $(ems[1]).text().trim();
                } else if (ems.length === 1) {
                    address = $(ems[0]).text().trim();
                }

                const detailText = cpInfoDiv.text();

                jobs.push({
                    source: "고용24",
                    company,
                    title,
                    address,
                    career,
                    education,
                    detailText,
                    url: link
                });
            });
        }
    } catch (e) {
        console.error(`고용24 크롤링 에러 (${keyword}):`, e.message);
    }
    return jobs;
}

// 2. 인크루트 (Incruit) 크롤러
async function scrapeIncruit(keyword) {
    const encodedKeyword = encodeURIComponent(keyword);
    const url = `https://search.incruit.com/list/search.asp?col=job&kw=${encodedKeyword}`;
    const headers = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
    };

    const jobs = [];
    try {
        const response = await axios.get(url, { 
            headers, 
            responseType: 'arraybuffer',
            timeout: 10000 
        });

        if (response.status === 200) {
            const decoder = new TextDecoder('euc-kr');
            const decodedHtml = decoder.decode(response.data);
            const $ = cheerio.load(decodedHtml);

            const cols = $("li.c_col");
            cols.each((index, element) => {
                const col = $(element);

                const cellFirst = col.find("div.cell_first");
                if (cellFirst.length === 0) return;
                const companyAnchor = cellFirst.find("a").first();
                const company = companyAnchor.length ? companyAnchor.text().trim() : cellFirst.text().trim();

                const cellMid = col.find("div.cell_mid");
                if (cellMid.length === 0) return;
                const jobAnchor = cellMid.find("a").first();
                if (jobAnchor.length === 0) return;

                const title = jobAnchor.text().trim();
                let link = jobAnchor.attr('href') || '';
                if (link && !link.startsWith('http')) {
                    link = "https://job.incruit.com" + link;
                }

                const clMd = cellMid.find(".cl_md");
                let address = "지역무관";
                let career = "관계없음";
                let education = "학력무관";
                let detailText = "";

                if (clMd.length) {
                    const mdText = clMd.text().trim();
                    detailText = mdText;

                    const careerIdx = mdText.indexOf("경력");
                    const freshmanIdx = mdText.indexOf("신입");
                    let cutIdx = -1;

                    if (careerIdx !== -1 && freshmanIdx !== -1) {
                        cutIdx = Math.min(careerIdx, freshmanIdx);
                    } else if (careerIdx !== -1) {
                        cutIdx = careerIdx;
                    } else if (freshmanIdx !== -1) {
                        cutIdx = freshmanIdx;
                    }

                    if (cutIdx !== -1) {
                        address = mdText.substring(0, cutIdx).trim();
                        const remainder = mdText.substring(cutIdx);

                        const eduKeywords = ["학력무관", "고졸", "대졸", "초대졸", "대학졸업", "대학교졸업", "석사", "박사"];
                        let matchedEdu = "";
                        for (const eduKey of eduKeywords) {
                            if (remainder.includes(eduKey)) {
                                matchedEdu = eduKey;
                                break;
                            }
                        }

                        if (matchedEdu) {
                            education = matchedEdu;
                            const eduIdx = remainder.indexOf(matchedEdu);
                            career = remainder.substring(0, eduIdx).trim();
                        } else {
                            career = remainder.trim();
                        }
                    } else {
                        address = mdText;
                    }
                }

                jobs.push({
                    source: "인크루트",
                    company,
                    title,
                    address,
                    career,
                    education,
                    detailText,
                    url: link
                });
            });
        }
    } catch (e) {
        console.error(`인크루트 크롤링 에러 (${keyword}):`, e.message);
    }
    return jobs;
}

// 3. 사람인 (Saramin) 크롤러 추가
async function scrapeSaramin(keyword) {
    const encodedKeyword = encodeURIComponent(keyword);
    const url = `https://www.saramin.co.kr/zf_user/search?searchword=${encodedKeyword}`;
    const headers = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
        "Referer": "https://www.saramin.co.kr/"
    };

    const jobs = [];
    try {
        const response = await axios.get(url, { headers, timeout: 10000 });
        if (response.status === 200) {
            const $ = cheerio.load(response.data);
            const items = $(".item_recruit");

            items.each((index, element) => {
                const item = $(element);

                const corpAnchor = item.find(".corp_name a");
                const company = corpAnchor.length ? corpAnchor.text().trim() : "회사명 비공개";

                const jobAnchor = item.find(".job_tit a");
                if (jobAnchor.length === 0) return;

                const title = jobAnchor.text().trim();
                let link = jobAnchor.attr('href') || '';
                if (link && !link.startsWith('http')) {
                    link = "https://www.saramin.co.kr" + link;
                }

                const condSpans = item.find(".job_condition span");
                let address = "지역무관";
                let career = "관계없음";
                let education = "학력무관";

                condSpans.each((idx, span) => {
                    const text = $(span).text().trim();
                    if (text.includes("서울") || text.includes("경기") || text.includes("인천") || text.includes("지역") || text.includes("전국") || text.includes("충남") || text.includes("부산") || text.includes("대구") || text.includes("광주") || text.includes("대전") || text.includes("세종")) {
                        address = text;
                    } else if (text.includes("경력") || text.includes("신입") || text.includes("무관")) {
                        career = text;
                    } else if (text.includes("대졸") || text.includes("고졸") || text.includes("초대졸") || text.includes("대학") || text.includes("석사") || text.includes("박사") || text.includes("학력")) {
                        education = text;
                    }
                });

                const detailText = `${title} | ${address} | ${career} | ${education}`;

                jobs.push({
                    source: "사람인",
                    company,
                    title,
                    address,
                    career,
                    education,
                    detailText,
                    url: link
                });
            });
        }
    } catch (e) {
        console.error(`사람인 크롤링 에러 (${keyword}):`, e.message);
    }
    return jobs;
}

