exports.code = async (inputs) => {
    console.log("[Activepieces 스크래퍼 디버그] 수신된 raw inputs 데이터:", JSON.stringify(inputs, null, 2));

    let jobsList = findValueByKey(inputs, 'primary_jobs') || findValueByKey(inputs, 'primary_job');

    // 강제 세탁 (기호 완벽 제거)
    if (typeof jobsList === 'string') {
        jobsList = jobsList.replace(/[\[\]'"]/g, '').trim();
    }

    if (jobsList && !Array.isArray(jobsList)) {
        jobsList = [jobsList];
    }

    if (jobsList.length === 1 && typeof jobsList[0] === 'string' && jobsList[0].includes(',')) {
        jobsList = jobsList[0].split(',').map(s => s.trim()).filter(Boolean);
    }

    const keywords = (jobsList && jobsList.length > 0 && jobsList[0] !== '') ? jobsList : ['UIUX 디자이너'];

    const latVal = findValueByKey(inputs, 'user_latitude') || findValueByKey(inputs, 'latitude');
    const lonVal = findValueByKey(inputs, 'user_longitude') || findValueByKey(inputs, 'longitude');
    const distVal = findValueByKey(inputs, 'max_distance') || findValueByKey(inputs, 'max_distance_km');
    const careerVal = findValueByKey(inputs, 'career');
    const eduVal = findValueByKey(inputs, 'education');

    const userLat = parseFloat(latVal) || 37.5565;
    const userLon = parseFloat(lonVal) || 126.9780;
    const maxDistance = parseFloat(distVal) || 10.0;
    const requiredCareer = careerVal || '관계없음';

    const crawlPromises = [];
    for (const kw of keywords) {
        crawlPromises.push(scrapeWorknet(kw));  // 고용24 크롤링 시작
        crawlPromises.push(scrapeIncruit(kw));  // 인크루트 크롤링 시작
        crawlPromises.push(scrapeSaramin(kw));  // 사람인 크롤링 시작
    }

    const allResults = await Promise.all(crawlPromises);
    const combinedJobs = allResults.flat();

    // 중복 데이터 제거
    const seen = new Set();
    const uniqueCombinedJobs = combinedJobs.filter(j => {
        const duplicateKey = `${j.company}_${j.title}`;
        if (seen.has(duplicateKey)) return false;
        seen.add(duplicateKey);
        return true;
    });

    const matchedWorknet = [];
    const matchedIncruit = [];
    const matchedSaramin = [];
    const aiKeywords = ['ai', '인공지능', '러닝', 'gpt', 'llm', '머신러닝', '딥러닝'];

    // 거리 계산 및 필터링
    for (const j of uniqueCombinedJobs) {
        let jobLat = userLat;
        let jobLon = userLon;
        const address = j.address;

        if (address.includes("강남") || address.includes("서초") || address.includes("역삼") || address.includes("선릉")) {
            jobLat = 37.4979; jobLon = 127.0276;
        } else if (address.includes("마포") || address.includes("공덕") || address.includes("합정") || address.includes("신촌")) {
            jobLat = 37.5458; jobLon = 126.9534;
        } else if (address.includes("여의도") || address.includes("영등포") || address.includes("당산")) {
            jobLat = 37.5255; jobLon = 126.9244;
        } else if (address.includes("구로") || address.includes("가산") || address.includes("독산")) {
            jobLat = 37.4785; jobLon = 126.8856;
        } else if (address.includes("성수") || address.includes("뚝섬") || address.includes("성동구")) {
            jobLat = 37.5446; jobLon = 127.0565;
        } else if (address.includes("종로") || address.includes("을지로") || address.includes("중구") || address.includes("시청")) {
            jobLat = 37.5665; jobLon = 126.9780;
        } else if (address.includes("판교") || address.includes("분당") || address.includes("성남")) {
            jobLat = 37.4012; jobLon = 127.1086;
        } else if (address.includes("지역무관") || address.includes("재택") || address.includes("재택근무")) {
            jobLat = userLat;
            jobLon = userLon;
        }

        const distance = calculateDistance(userLat, userLon, jobLat, jobLon);

        if (!address.includes("지역무관") && !address.includes("재택") && distance > maxDistance) {
            continue;
        }

        if (requiredCareer !== "관계없음") {
            if (requiredCareer === "신입" && !j.career.includes("신입") && !j.career.includes("무관")) {
                continue;
            }
            if (requiredCareer === "경력" && !j.career.includes("경력") && !j.career.includes("년")) {
                continue;
            }
        }

        const isAiRelated = aiKeywords.some(kw => 
            j.title.toLowerCase().includes(kw) || 
            (j.detailText && j.detailText.toLowerCase().includes(kw))
        );
        const displayTitle = isAiRelated ? `🔥 [AI우대] ${j.title}` : j.title;

        const processedJob = {
            company: j.company,
            title: displayTitle,
            address: j.address,
            career: j.career,
            education: j.education,
            isAi: isAiRelated,
            distance: (address.includes("지역무관") || address.includes("재택")) ? "재택/지역무관" : `${distance.toFixed(1)}km`,
            url: j.url
        };

        if (j.source === "고용24") {
            matchedWorknet.push(processedJob);
        } else if (j.source === "인크루트") {
            matchedIncruit.push(processedJob);
        } else if (j.source === "사람인") {
            matchedSaramin.push(processedJob);
        }
    }

    // AI 정렬 및 상위 5개 자르기
    const getTopFive = (jobs) => {
        return jobs.sort((a, b) => {
            if (a.isAi && !b.isAi) return -1;
            if (!a.isAi && b.isAi) return 1;
            return 0;
        }).slice(0, 5);
    };

    const displayWorknet = getTopFive(matchedWorknet);
    const displayIncruit = getTopFive(matchedIncruit);
    const displaySaramin = getTopFive(matchedSaramin);

    const buildHtmlList = (jobs) => {
        let listHtml = "";
        for (const j of jobs) {
            listHtml += `
            <li style="margin-bottom: 10px; list-style: none; padding: 12px; border-bottom: 1px solid #f3f4f6; font-family: sans-serif; background-color: #fafafa; border-radius: 6px;">
                <strong style="color: #4f46e5; font-size: 1.05em;">${j.company}</strong><br>
                <a href="${j.url}" target="_blank" style="text-decoration: none; color: #1e293b; font-weight: bold; font-size: 1em; line-height: 1.4; display: inline-block; margin-top: 2px;">${j.title}</a><br>
                <span style="color: #64748b; font-size: 0.85em; display: inline-block; margin-top: 4px;">📍 ${j.address} (${j.distance}) | 💼 ${j.career} | 🎓 ${j.education}</span>
            </li>
            `;
        }
        return listHtml;
    };

    const worknetListHtml = buildHtmlList(displayWorknet);
    const incruitListHtml = buildHtmlList(displayIncruit);
    const saraminListHtml = buildHtmlList(displaySaramin);

    // 사용자가 입력한 희망 기준 주소 추출 및 지역 키워드 생성
    const rawAddress = findValueByKey(inputs, 'address') || '';
    const regionKeyword = rawAddress ? rawAddress.split(' ').slice(0, 2).join(' ') : '';

    // 첫 번째 검색어로 대표 외부 아웃링크 생성
    const primaryKeyword = keywords[0];
    const searchCombo = regionKeyword ? `${primaryKeyword} ${regionKeyword}` : primaryKeyword;
    const encodedKW = encodeURIComponent(searchCombo);
    const worknetSearchLink = `https://www.work.go.kr/empInfo/empInfoSrch/list/dtlEmpSrchList.do?searchOn=Y&srcKeyword=${encodedKW}`;
    const incruitSearchLink = `https://search.incruit.com/list/search.asp?col=job&kw=${encodedKW}`;
    const saraminSearchLink = `https://www.saramin.co.kr/zf_user/search?searchword=${encodedKW}`;

    const totalCount = matchedWorknet.length + matchedIncruit.length + matchedSaramin.length;

    // 메일 본문 HTML 빌드
    let mailBody = `
    <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; padding: 15px; background-color: #ffffff; border-radius: 12px; border: 1px solid #e2e8f0; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);">
        <h2 style="color: #0f172a; border-bottom: 2px solid #4f46e5; padding-bottom: 10px; margin-top: 0; font-size: 1.3em;">📢 AI 채용 큐레이션 데일리 리포트</h2>

        <p style="color: #475569; font-size: 0.95em; line-height: 1.5; margin-bottom: 20px;">
            AI 분석 직무 키워드 [<strong>${keywords.join(', ')}</strong>]에 부합하는 추천 공고입니다. (총 <strong>${totalCount}건</strong> 검색됨)
        </p>

        <!-- 🔵 고용24 섹션 -->
        <div id="worknet-section" style="margin-bottom: 30px; border-top: 1px solid #e2e8f0; padding-top: 20px;">
            <h3 style="color: #1e40af; background-color: #eff6ff; padding: 8px 12px; border-radius: 6px; font-size: 1.05em; margin-top: 0; margin-bottom: 15px; border-left: 4px solid #3b82f6;">
                🔵 고용24 (워크넷) 추천 공고 (${matchedWorknet.length}건 중 상위 5개 노출)
            </h3>
            ${worknetListHtml ? `<ul style="padding: 0; margin: 0;">${worknetListHtml}</ul>` : `<p style="color: #94a3b8; margin: 0; padding: 12px;">매칭되는 고용24 공고가 없습니다.</p>`}

            ${matchedWorknet.length > 5 ? `
            <div style="text-align: center; margin-top: 15px;">
                <a href="${worknetSearchLink}" target="_blank" style="display: inline-block; padding: 8px 16px; background-color: #3b82f6; color: white; text-decoration: none; font-weight: bold; font-size: 0.85em; border-radius: 6px;">👉 고용24에서 결과 전체 보기</a>
            </div>` : ''}
        </div>

        <!-- 🟢 인크루트 섹션 -->
        <div id="incruit-section" style="margin-bottom: 30px; border-top: 1px solid #e2e8f0; padding-top: 20px;">
            <h3 style="color: #065f46; background-color: #ecfdf5; padding: 8px 12px; border-radius: 6px; font-size: 1.05em; margin-top: 0; margin-bottom: 15px; border-left: 4px solid #10b981;">
                🟢 인크루트 추천 공고 (${matchedIncruit.length}건 중 상위 5개 노출)
            </h3>
            ${incruitListHtml ? `<ul style="padding: 0; margin: 0;">${incruitListHtml}</ul>` : `<p style="color: #94a3b8; margin: 0; padding: 12px;">매칭되는 인크루트 공고가 없습니다.</p>`}

            ${matchedIncruit.length > 5 ? `
            <div style="text-align: center; margin-top: 15px;">
                <a href="${incruitSearchLink}" target="_blank" style="display: inline-block; padding: 8px 16px; background-color: #10b981; color: white; text-decoration: none; font-weight: bold; font-size: 0.85em; border-radius: 6px;">👉 인크루트에서 결과 전체 보기</a>
            </div>` : ''}
        </div>

        <!-- 🟠 사람인 섹션 -->
        <div id="saramin-section" style="margin-bottom: 30px; border-top: 1px solid #e2e8f0; padding-top: 20px;">
            <h3 style="color: #c2410c; background-color: #fff7ed; padding: 8px 12px; border-radius: 6px; font-size: 1.05em; margin-top: 0; margin-bottom: 15px; border-left: 4px solid #f97316;">
                🟠 사람인 추천 공고 (${matchedSaramin.length}건 중 상위 5개 노출)
            </h3>
            ${saraminListHtml ? `<ul style="padding: 0; margin: 0;">${saraminListHtml}</ul>` : `<p style="color: #94a3b8; margin: 0; padding: 12px;">매칭되는 사람인 공고가 없습니다.</p>`}

            ${matchedSaramin.length > 5 ? `
            <div style="text-align: center; margin-top: 15px;">
                <a href="${saraminSearchLink}" target="_blank" style="display: inline-block; padding: 8px 16px; background-color: #f97316; color: white; text-decoration: none; font-weight: bold; font-size: 0.85em; border-radius: 6px;">👉 사람인에서 결과 전체 보기</a>
            </div>` : ''}
        </div>

        <p style="color: #94a3b8; font-size: 0.8em; text-align: center; margin-top: 40px; border-top: 1px solid #e2e8f0; padding-top: 15px;">
            본 메일은 수신 동의에 기반해 매일 아침 자동으로 발송되는 알림 메일입니다.
        </p>
    </div>
    `;

    const allMatchedJobs = [
        ...matchedWorknet.map(j => ({ ...j, source: "고용24" })),
        ...matchedIncruit.map(j => ({ ...j, source: "인크루트" })),
        ...matchedSaramin.map(j => ({ ...j, source: "사람인" }))
    ];

    return { 
        status: "success", 
        jobs: allMatchedJobs, 
        mail_body: mailBody 
    };
};
